352	async function dispatchApifyRuns(params: {
353	  supabaseUrl: string;
354	  webhookSecret: string;
355	  link: SocialLinkRow;
356	}): Promise<{
357	  metricsStatus: Partial<Record<MetricsKey, MetricsStatus>>;
358	  allFailed: boolean;
359	}> {
360	  const { supabaseUrl, webhookSecret, link } = params;
361	  const metricsStatus: Partial<Record<MetricsKey, MetricsStatus>> = {};
362	
363	  const webhookUrl = `${supabaseUrl}/functions/v1/apify-webhook`;
364	  const buildWebhook = (
365	    linkId: string,
366	    scrapeMode: "tiktok_profile" | "ig_details" | "ig_posts",
367	  ): ApifyWebhookSpec => ({
368	    eventTypes: APIFY_TERMINAL_EVENTS,
369	    requestUrl: webhookUrl,
370	    payloadTemplate: JSON.stringify({
371	      eventType: "{{eventType}}",
372	      resource: {
373	        id: "{{resource.id}}",
374	        defaultDatasetId: "{{resource.defaultDatasetId}}",
375	        status: "{{resource.status}}",
376	        actId: "{{resource.actId}}",
377	      },
378	      social_link_id: linkId,
379	      scrape_mode: scrapeMode,
380	      run_id: "{{resource.id}}",
381	      dataset_id: "{{resource.defaultDatasetId}}",
382	    }),
383	    headersTemplate: JSON.stringify({
384	      "X-Apify-Webhook-Secret": webhookSecret,
385	    }),
386	    shouldInterpolateStrings: true,
387	  });
388	
389	  interface Task {
390	    key: MetricsKey;
391	    run: () => Promise<ApifyRunResult>;
392	  }
393	  const tasks: Task[] = [];
394	  if (link.platform === "tiktok") {
395	    tasks.push({
396	      key: "tiktok",
397	      run: () =>
398	        runTikTokProfile(link.handle, {
399	          waitSecs: APIFY_WAIT_SECS,
400	          webhooks: [buildWebhook(link.id, "tiktok_profile")],
401	        }),
402	    });
403	  } else if (link.platform === "instagram") {
404	    tasks.push({
405	      key: "ig_details",
406	      run: () =>
407	        runInstagramDetails(link.handle, {
408	          waitSecs: APIFY_WAIT_SECS,
409	          webhooks: [buildWebhook(link.id, "ig_details")],
410	        }),
411	    });
412	    tasks.push({
413	      key: "ig_posts",
414	      run: () =>
415	        runInstagramPosts(link.handle, {
416	          waitSecs: APIFY_WAIT_SECS,
417	          webhooks: [buildWebhook(link.id, "ig_posts")],
418	        }),
419	    });
420	  }
421	
422	  const settled = await Promise.allSettled(tasks.map((t) => t.run()));
423	  let rejectedCount = 0;
424	  settled.forEach((outcome, i) => {
425	    const key = tasks[i].key;
426	    if (outcome.status === "fulfilled") {
427	      const s = outcome.value.status;
428	      metricsStatus[key] = s === "SUCCEEDED"
429	        ? "fresh"
430	        : s === "READY" || s === "RUNNING" ||
431	            s === "TIMING-OUT" || s === "ABORTING"
432	        ? "refreshing"
433	        : "failed";
434	    } else {
435	      rejectedCount += 1;
436	      console.error(`apify ${key} dispatch failed`, outcome.reason);
437	      metricsStatus[key] = "failed";
438	    }
439	  });
440	
441	  // `allFailed` flags the case where every task rejected at the transport
442	  // layer (Apify down, credentials rejected, etc.). Partial failures or
443	  // terminal-but-non-SUCCEEDED statuses stay on 200 with per-key 'failed'
444	  // so the client can still render whatever succeeded.
445	  const allFailed = tasks.length > 0 && rejectedCount === tasks.length;
446	  return { metricsStatus, allFailed };
447	}
